const payload = $json ?? {};
const execution = payload.execution ?? {};
const workflow = payload.workflow ?? {};
const error = execution.error ?? payload.error ?? {};
const now = new Date().toISOString();

const esc = (value = '') => String(value)
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;');

const shortText = (value, limit = 6000) => {
  if (value === undefined || value === null || value === '') return '';
  const text = typeof value === 'string' ? value : JSON.stringify(value, null, 2);
  const compact = text.replace(/\n{4,}/g, '\n\n\n').trim();
  return compact.length > limit ? compact.slice(0, limit) + '\n... (' + compact.length + ' Zeichen gesamt)' : compact;
};

const executionId = String(execution.id ?? '').trim();
const workflowName = String(workflow.name ?? payload.workflowName ?? 'Unbekannter Workflow').trim();
const workflowId = String(workflow.id ?? payload.workflowId ?? '').trim();
const lastNode = String(execution.lastNodeExecuted ?? execution.lastNode ?? '').trim();
const message = String(error.message ?? error.description ?? payload.message ?? 'Unbekannter Fehler').trim();
const stack = String(error.stack ?? '').trim();
const mode = String(execution.mode ?? '').trim();
const url = String(execution.url ?? '').trim();
const retryOf = String(execution.retryOf ?? '').trim();
const fileName = 'SollProzess_Fehlerprotokoll_' + (executionId || now.replace(/[:.]/g, '-')) + '.md';

const lines = [];
lines.push('# Fehlerprotokoll SollProzess');
lines.push('');
lines.push('Erstellt: ' + now);
lines.push('Workflow: ' + workflowName + (workflowId ? ' (' + workflowId + ')' : ''));
if (executionId) lines.push('Execution-ID: ' + executionId);
if (url) lines.push('Execution-URL: ' + url);
if (mode) lines.push('Ausführungsmodus: ' + mode);
if (retryOf) lines.push('Retry von Execution: ' + retryOf);
if (lastNode) lines.push('Letzter Node / Fehlernode: ' + lastNode);
lines.push('Status: technischer Fehler');
lines.push('');
lines.push('## Fehlermeldung');
lines.push('');
lines.push(message || 'Keine Fehlermeldung vorhanden.');
if (stack) {
  lines.push('', '## Stacktrace', '', '~~~text', shortText(stack, 10000), '~~~');
}
lines.push('', '## Rohdaten Error Trigger', '', '~~~json', shortText(payload, 12000), '~~~');

const markdown = lines.join('\n') + '\n';
const html = '<div style="font-family:Arial,sans-serif;color:#1f2937;line-height:1.45">'
  + '<h2>SollProzess - Fehlerprotokoll</h2>'
  + '<p>Ein Workflow-Fehler wurde durch den n8n Error Trigger abgefangen. Das Markdown-Protokoll ist angehängt.</p>'
  + '<p><b>Workflow:</b> ' + esc(workflowName) + '<br>'
  + '<b>Execution-ID:</b> ' + esc(executionId || 'nicht vorhanden') + '<br>'
  + '<b>Fehlernode:</b> ' + esc(lastNode || 'nicht vorhanden') + '<br>'
  + '<b>Fehler:</b> ' + esc(message || 'Unbekannter Fehler') + '</p>'
  + (url ? '<p><a href="' + esc(url) + '">Execution in n8n öffnen</a></p>' : '')
  + '</div>';

return [{
  json: {
    workflow_id: workflowId,
    workflow_name: workflowName,
    execution_id: executionId,
    execution_url: url,
    error_node: lastNode,
    error_message: message,
    fehler_protokoll_markdown: markdown,
    fehler_protokoll_dateiname: fileName,
    fehler_protokoll_mail_html: html,
  },
  binary: {
    fehler_protokoll: {
      data: Buffer.from(markdown, 'utf8').toString('base64'),
      mimeType: 'text/markdown',
      fileName,
    },
  },
}];
